publicApiVersions.query:
#graphql
  query PublicApiVersionsRead {
    publicApiVersions {
      handle
      displayName
      supported
    }
  }

nodeNoData.query:
#graphql
  query NodeNoDataRead($ids: [ID!]!) {
    node(id: "gid://shopify/Product/0") {
      __typename
      id
    }
    nodes(ids: $ids) {
      __typename
      id
    }
  }

jobDomainNoData.query:
#graphql
  query JobDomainNoDataRead($domainId: ID!, $jobId: ID!) {
    domain(id: $domainId) {
      id
      host
      url
      sslEnabled
    }
    job(id: $jobId) {
      id
      done
      query {
        __typename
      }
    }
  }

backupRegion.query:
#graphql
  query BackupRegionRead {
    backupRegion {
      __typename
      id
      name
      ... on MarketRegionCountry {
        code
      }
    }
  }

taxonomyEmptySearch.query:
#graphql
  query TaxonomyEmptySearchRead {
    taxonomy {
      categories(first: 2, search: "zzzzzz-no-match-har-315") {
        nodes {
          id
          name
          fullName
          isRoot
          isLeaf
          level
          parentId
          ancestorIds
          childrenIds
          isArchived
        }
        edges {
          cursor
          node {
            id
            name
          }
        }
        pageInfo {
          hasNextPage
          hasPreviousPage
          startCursor
          endCursor
        }
      }
    }
  }

supportedNodeSeeds.query:
#graphql
  query SupportedNodeSeedRead {
    products(first: 1) {
      nodes {
        id
        title
        handle
      }
    }
    collections(first: 1) {
      nodes {
        id
        title
        handle
      }
    }
    customers(first: 1) {
      nodes {
        id
        displayName
        email
      }
    }
    locations(first: 1) {
      nodes {
        id
        name
        isActive
      }
    }
  }

supportedNodes.query:
#graphql
  query SupportedNodeRead($ids: [ID!]!) {
    nodes(ids: $ids) {
      __typename
      ... on Node {
        id
      }
      ... on Product {
        title
        handle
      }
      ... on Collection {
        title
        handle
      }
      ... on Customer {
        displayName
        email
      }
      ... on Location {
        name
        isActive
      }
    }
  }

staffAccessBlocker.query:
#graphql
  query StaffUtilityRead {
    staffMember {
      id
      exists
      active
      isShopOwner
      accountType
    }
    staffMembers(first: 1) {
      nodes {
        id
        exists
        active
        isShopOwner
        accountType
      }
      edges {
        cursor
        node {
          id
          exists
          active
        }
      }
      pageInfo {
        hasNextPage
        hasPreviousPage
        startCursor
        endCursor
      }
    }
  }

flowTriggerReceiveInvalid.query:
#graphql
  mutation FlowTriggerReceiveInvalid {
    flowTriggerReceive(handle: "har-374-missing", payload: { test: "value" }) {
      userErrors {
        field
        message
      }
    }
  }

flowTriggerReceiveOversize.query:
#graphql
  mutation FlowTriggerReceiveOversize($payload: JSON) {
    flowTriggerReceive(handle: "har-374-missing", payload: $payload) {
      userErrors {
        field
        message
      }
    }
  }

flowGenerateSignatureUnknown.query:
mutation {
  flowGenerateSignature(id: "gid://shopify/FlowTrigger/0", payload: "{}") {
    signature
    userErrors {
      field
      message
    }
  }
}

backupRegionUpdateIdempotent.query:
#graphql
  mutation BackupRegionUpdateIdempotent {
    backupRegionUpdate(region: { countryCode: CA }) {
      backupRegion {
        __typename
        id
        name
        ... on MarketRegionCountry {
          code
        }
      }
      userErrors {
        field
        message
        code
      }
    }
  }

